**代码片段** - 虚拟页号索引计算：
```rust
impl VirtPageNum {
    pub fn indexes(&self) -> [usize; 3] {
        let mut vpn = self.0;
        let mut idx = [0usize; 3];
        for i in (0..3).rev() {
            idx[i] = vpn & 511;  // 每级页表 9 位索引
            vpn >>= 9;
        }
        idx
    }
}
